// Obtenha o texto da entrada
let inputText = $input.first().json.output || "";

// --- LÓGICA DE DETECÇÃO DE ÁUDIO ALTERADA ---
// Verifica se a mensagem é do tipo 'AudioMessage' com base na expression fornecida.
// Usando optional chaining (?) para evitar erros caso a estrutura do objeto não exista.
const messageType = $('Webhook').item.json.body.message?.messageType;
const isAudioMessage = messageType === 'AudioMessage';


// Converte markdown de links [texto](url) para "texto\nurl"
const markdownRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
inputText = inputText.replace(markdownRegex, (match, texto, url) => {
    return `${texto}\n${url}`;
});

// Separe o texto em um array, removendo linhas vazias
const originalTextBlocks = inputText.split('\n').filter(block => block.trim() !== ""); // Renomeado para clareza

// --- Funções Auxiliares ---

// Função para identificar o tipo de mídia a partir de uma URL
const determineMediaType = (url) => {
    const tipoMatch = url.match(/[?&]tipo=([^&]+)/);
    if (tipoMatch) {
        return tipoMatch[1].replace(/[)(\s]/g, '').toLowerCase();
    }
    const cleanUrl = url.split('?')[0].split('#')[0];
    if (/\.pdf$/i.test(cleanUrl)) return 'pdf';
    if (/\.(doc|docx|txt|rtf|odt)$/i.test(cleanUrl)) return 'doc';
    if (/\.(jpg|jpeg|png|gif|bmp|svg|webp|tiff|ico|heic|heif)$/i.test(cleanUrl)) return 'image';
    if (/\.(mp4|mov|avi|wmv|mkv|flv|webm|3gp|m4v)$/i.test(cleanUrl)) return 'video';
    if (/\.(mp3|wav|ogg|m4a|aac|flac|wma)$/i.test(cleanUrl)) return 'audioMessage';
    if (url.includes('drive.google.com') || url.includes('dropbox.com') || url.includes('onedrive.com')) {
        if (/\/[^\/]*\.pdf/i.test(url)) return 'pdf';
        if (/\/[^\/]*\.(jpg|jpeg|png|gif|bmp|svg|webp)/i.test(url)) return 'image';
        if (/\/[^\/]*\.(mp4|mov|avi|wmv|mkv|flv)/i.test(url)) return 'video';
    }
    if (url.includes('contentType=application/pdf') || url.includes('mimetype=application/pdf')) return 'pdf';
    if (url.includes('contentType=image/') || url.includes('mimetype=image/')) return 'image';
    if (url.includes('contentType=video/') || url.includes('mimetype=video/')) return 'video';
    return null; // Retorna null se nenhum tipo for detectado
};

// Função para extrair a primeira URL de um texto
const extractUrl = (text) => {
    const urlRegex = /(https?:\/\/[^\s<>"'`,{}|\\^\[\]()]+)/g;
    const match = text.match(urlRegex);
    return match ? match[0] : null;
};

// Função para limpar o texto, removendo a URL e parênteses vazios
const cleanTextFromUrl = (text, url) => {
    let cleaned = text;
    if (url) {
        cleaned = text.replace(url, '');
    }
    // Remove parênteses que contêm apenas espaços em branco
    return cleaned.replace(/\s*\(\s*\)\s*/g, '').trim();
};

// --- Lógica de Processamento ---

let intermediateOutput = []; // Usado para armazenar todos os blocos na ordem original antes da decisão final do tipo
let hasVisualMediaInAnyBlock = false; // Flag para saber se há qualquer imagem/pdf/video na saída

// Primeiro passo: Classificar cada bloco e identificar se há mídia visual
for (const block of originalTextBlocks) {
    const url = extractUrl(block);
    const mediaType = url ? determineMediaType(url) : null;
    const text = cleanTextFromUrl(block, url);

    if (mediaType === 'pdf' || mediaType === 'image' || mediaType === 'video') {
        intermediateOutput.push({
            block: url,
            text: text || null,
            type: mediaType // Tipo específico para mídia
        });
        hasVisualMediaInAnyBlock = true; // Define a flag
    } else {
        intermediateOutput.push({
            block: null,
            text: block, // Mantém o bloco de texto original por enquanto
            type: 'placeholder' // Usamos um placeholder para texto puro por enquanto
        });
    }
}

// Segundo passo: Determinar o tipo final para os blocos de texto (placeholder)
let finalOutputArray = [];
let currentConversationBlock = []; // Acumulador para agrupar conversações em até 4 blocos

const processConversationBlocks = (blocksToProcess, defaultType, isAudio) => {
    if (blocksToProcess.length === 0) return;

    const combinedText = blocksToProcess.join('\n');
    const contentLines = combinedText.split('\n').filter(line => line.trim() !== "");

    // --- ALTERAÇÃO: Se for áudio, envia tudo em um único bloco ---
    if (isAudio) {
        finalOutputArray.push({
            block: null,
            text: combinedText,
            type: defaultType
        });
        return;
    }

    // Mantém a lógica original para não-áudio
    const maxBlocks = 4;

    if (contentLines.length <= maxBlocks) {
        contentLines.forEach(line => {
            finalOutputArray.push({
                block: null,
                text: line,
                type: defaultType
            });
        });
    } else {
        // Lógica de agrupamento para mais de 4 linhas: 1a, 2a, resto (exceto última), última
        const lastLineIndex = contentLines.length - 1;
        finalOutputArray.push({ block: null, text: contentLines[0], type: defaultType });
        finalOutputArray.push({ block: null, text: contentLines[1], type: defaultType });
        finalOutputArray.push({ block: null, text: contentLines.slice(2, lastLineIndex).join('\n'), type: defaultType });
        finalOutputArray.push({ block: null, text: contentLines[lastLineIndex], type: defaultType });
    }
};

// Determina o tipo padrão para os blocos de texto puros
let defaultGroupedTypeForText = 'conversation';
// --- LÓGICA DE ATRIBUIÇÃO DE TIPO ALTERADA ---
// Utiliza a nova variável 'isAudioMessage' para definir o tipo padrão.
if (isAudioMessage && !hasVisualMediaInAnyBlock) {
    defaultGroupedTypeForText = 'audioMessage';
}

// Terceiro passo: Iterar sobre intermediateOutput para montar o finalOutputArray,
// respeitando a ordem e agrupando blocos de texto
for (const item of intermediateOutput) {
    if (item.type === 'placeholder') {
        // Se for um bloco de texto, adicione ao acumulador
        currentConversationBlock.push(item.text);
    } else {
        // Se for um bloco de mídia (pdf, image, video), primeiro processe os blocos de conversa acumulados
        processConversationBlocks(currentConversationBlock, defaultGroupedTypeForText, isAudioMessage);
        currentConversationBlock = []; // Reseta o acumulador
        finalOutputArray.push(item); // Adiciona o bloco de mídia
    }
}

// Processa quaisquer blocos de conversa restantes no final
processConversationBlocks(currentConversationBlock, defaultGroupedTypeForText, isAudioMessage);


// Formatar a saída final, garantindo que não haja blocos vazios
return finalOutputArray
    .filter(item => (item.block && item.block.trim()) || (item.text && item.text.trim()))
    .map(item => ({ json: item }));

// Obtém a transcrição do OCR
const transcription = items[0].json.responses[0].textAnnotations[0].description;

// Cria um objeto para o resultado final
let output = {};

// 1. VERIFICA SE O VALE É DA "PAIZÃO DO GÁS"
// A regex busca por "paizão" ou "paizao" (case-insensitive) para ser mais robusta a erros de OCR.
const marcaRegex = /paiz(ã|a)o/i;
const isPaizaoDoGas = marcaRegex.test(transcription);
output.isPaizaoDoGas = isPaizaoDoGas;

// 2. EXTRAI O NÚMERO DO VALE (SEQUÊNCIA DE 4 DÍGITOS)
// A expressão regular busca por uma sequência isolada de exatamente 4 dígitos.
// \b -> garante que estamos pegando um "bloco" de número separado.
// \d{4} -> especifica que queremos exatamente 4 dígitos.
const numeroRegex = /\b(\d{4})\b/g;

// Tenta encontrar o padrão numérico na transcrição
const match = transcription.match(numeroRegex);

// 3. VALIDA E RETORNA O RESULTADO
if (match && match.length > 0) {
    // Se encontrou (mesmo que duplicado), pega o primeiro resultado.
    // Isso funciona tanto para o caso com canhoto (dois números) quanto sem (um número).
    const numeroDoVale = match[0];
    output.numeroDoVale = numeroDoVale;
} else {
    // Se não encontrou, define uma mensagem de erro.
    output.numeroDoVale = 'Não foi possível detectar o número de 4 dígitos do vale. Por favor, envie uma nova imagem.';
}

// Retorna o objeto de saída completo
return [{ json: output }];
